pair F, O, P;

F = (-4,0);
O = (0,3);
P = intersectionpoint(F--O,Circle((0,3),2));

draw((-5,0)--(2,0));
draw((0,-1)--(0,6));
draw(Circle((0,3),2));
draw(F--O);

dot("$F_2$", F, S);
dot("$O$", O, E);
dot("$P$", P, S);
[/asy]

Therefore, the maximum value of $PQ + F_1 Q$ is $14 - 3 = \boxed{11}.$

